<script lang="ts">
  import { FileAudio, FileText, FileUp, History, Plus } from '@lucide/svelte';import { page } from '$app/state';import { api,uploadManagedFile } from '$lib/api';import PdfEditor from '$lib/PdfEditor.svelte';
  let sources=$state<any[]>([]);let uploading=$state(false);let progress=$state(0);let error=$state('');let pdf=$state<any>(null);const sessionId=String(page.params.id);
  async function load(){sources=(await api<{items:any[]}>(`/sessions/${sessionId}/sources`)).items}load();
  async function upload(event:Event){const input=event.currentTarget as HTMLInputElement;const file=input.files?.[0];if(!file)return;uploading=true;try{await uploadManagedFile(file,sessionId,(value)=>progress=value);await load()}catch(caught){error=caught instanceof Error?caught.message:String(caught)}finally{uploading=false;input.value=''}}
</script>
<div><div class="flex flex-wrap items-end justify-between gap-4"><div><h2 class="text-2xl font-semibold">Sources and versions</h2><p class="muted mt-2">Attach reusable material, inspect derived versions, and select the current source without overwriting history.</p></div><label class="flex cursor-pointer items-center gap-2 rounded-xl bg-[var(--accent)] px-4 py-2.5 text-sm font-semibold text-white"><FileUp size={16}/>{uploading?`${Math.round(progress*100)}%`:'Add source'}<input type="file" class="sr-only" onchange={upload}/></label></div>{#if error}<p class="mt-4 text-sm text-red-500">{error}</p>{/if}<div class="mt-6 grid gap-4 md:grid-cols-2">{#each sources as source}<article class:stale={!source.attachment.is_current} class="surface rounded-2xl p-5"><div class="flex items-start gap-3"><div class="grid size-10 place-items-center rounded-xl bg-[var(--accent-soft)] text-[var(--accent)]">{#if source.kind.match(/mp3|wav|flac|mp4|mkv/)}<FileAudio size={18}/>{:else}<FileText size={18}/>{/if}</div><div class="min-w-0 flex-1"><h3 class="truncate font-semibold">{source.display_name}</h3><div class="muted mt-1 text-xs uppercase">{source.kind} · {source.attachment.role} · {source.attachment.is_current?'current':'previous'}</div></div><History size={16}/></div><div class="mt-4 flex gap-2">{#if source.artifact_id}<a href={`/api/v1/artifacts/${source.artifact_id}/content`} target="_blank" class="action">Preview</a>{/if}{#if source.kind==='pdf'}<button onclick={()=>pdf={id:source.artifact_id,filename:source.display_name}} class="action">Preprocess PDF</button>{/if}</div></article>{:else}<div class="muted col-span-full rounded-2xl border border-dashed border-[var(--line)] p-10 text-center"><Plus class="mx-auto mb-2"/>Add the first source for this session.</div>{/each}</div></div>{#if pdf}<PdfEditor sessionId={sessionId} source={pdf} onclose={()=>pdf=null}/>{/if}
<style>.stale{opacity:.62}.action{border:1px solid var(--line);border-radius:.65rem;padding:.5rem .7rem;font-size:.72rem;font-weight:650}</style>
